// Standard binary search — always starts from middle
function upperLookup(uint256[] storage arr, uint256 key) internal view returns (uint256) {
    uint256 low = 0;
    uint256 high = arr.length;
    while (low < high) {
        uint256 mid = (low + high) / 2;
        if (arr[mid].key <= key) low = mid + 1;
        else high = mid;
    }
    return high == 0 ? 0 : arr[high - 1].value;
}

